def process_payment(user, cart_items, payment_details):
    # Calculate the total amount from cart items
    total_amount = sum(item['price'] * item['quantity'] for item in cart_items)
    
    # Define discount percentages based on user roles
    discount_percentages = {
        'basic': 0,
        'premium': 15,
        'enterprise': 30
    }
    
    # Get the discount percentage for the user's role
    discount_percentage = discount_percentages.get(user.role, 0)
    
    # Calculate the discount amount
