    # Apply the discount to the total amount
    final_amount = total_amount - discount_amount
    
    # Process the payment (simulated here with a print statement)
    print(f"Processing payment of ${final_amount} for {user.role} user.")
    
    # Return the final amount paid
    return final_amount

